('additional-maths:1-2-surds-and-algebraic-fractions:match:cc7eb282', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Conjugate of \\( 5 - \\sqrt{2} \\)”?", "options": ["\\( 2 - \\sqrt{3} \\)", "\\( 5 + \\sqrt{2} \\)", "\\( 3\\sqrt{2} \\)", "\\( 2\\sqrt{2} \\)"]}'::jsonb, '{"answer": 1, "explain": "“Conjugate of \\( 5 - \\sqrt{2} \\)” means: \\( 5 + \\sqrt{2} \\)"}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:match:300ff613', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “\\( \\dfrac{x^2 - 9}{x + 3} \\)”?", "options": ["\\( \\dfrac{\\sqrt{3}}{3} \\)", "\\( 5\\sqrt{5} \\)", "\\( 2 - \\sqrt{3} \\)", "\\( x - 3 \\)"]}'::jsonb, '{"answer": 3, "explain": "“\\( \\dfrac{x^2 - 9}{x + 3} \\)” means: \\( x - 3 \\)"}'::jsonb),
('additional-maths:1-2-surds-and-algebraic-fractions:match:6ccc8f1a', 'additional-maths', 'additional-maths:1-2-surds-and-algebraic-fractions', '1.2 Surds and Algebraic Fractions', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “\\( \\dfrac{x^2 + 5x + 6}{x^2 - 4} \\)”?", "options": ["\\( 4\\sqrt{3} \\)", "\\( \\dfrac{x+3}{x-2} \\)", "\\( \\dfrac{\\sqrt{3}}{3} \\)", "\\( x - 3 \\)"]}'::jsonb, '{"answer": 1, "explain": "“\\( \\dfrac{x^2 + 5x + 6}{x^2 - 4} \\)” means: \\( \\dfrac{x+3}{x-2} \\)"}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:mcq:b5897ada', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'mcq', 'mcq', 1, '{"question": "Express \\( x^2 + 10x + 7 \\) in completed-square form.", "options": ["\\( (x+5)^2 - 18 \\)", "\\( (x+5)^2 + 7 \\)", "\\( (x+10)^2 - 18 \\)", "\\( (x+5)^2 - 32 \\)"]}'::jsonb, '{"answer": 0, "explain": "Half of 10 is 5; \\( (x+5)^2 = x^2+10x+25 \\), 25 too big, so \\( (x+5)^2 - 25 + 7 = (x+5)^2 - 18 \\)."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:mcq:70730f85', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'mcq', 'mcq', 1, '{"question": "A student writes \\( x^2 + 12x - 4 = (x+6)^2 - 4 \\). What is wrong?", "options": ["They forgot to subtract \\( 36 \\): it should be \\( (x+6)^2 - 40 \\)", "Nothing — it is correct", "It should be \\( (x+12)^2 - 4 \\)", "\\( (x+6)^2 \\) should be \\( (x-6)^2 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( (x+6)^2 = x^2+12x+36 \\), so you must subtract 36 as well as keeping the \\( -4 \\): \\( (x+6)^2 - 40 \\)."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:mcq:d23e7e1e', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'mcq', 'mcq', 1, '{"question": "Complete the square for \\( 3x^2 + 6x + 1 \\).", "options": ["\\( 3(x+1)^2 - 2 \\)", "\\( 3(x+1)^2 + 1 \\)", "\\( (3x+1)^2 - 2 \\)", "\\( 3(x+1)^2 - 3 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( 3(x^2+2x)+1 = 3[(x+1)^2 - 1] + 1 = 3(x+1)^2 - 3 + 1 = 3(x+1)^2 - 2 \\)."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:mcq:d061c70f', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'mcq', 'mcq', 1, '{"question": "What is the minimum value of \\( x^2 - 8x + 3 \\)?", "options": ["\\( -13 \\)", "\\( 3 \\)", "\\( -8 \\)", "\\( 13 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( (x-4)^2 - 16 + 3 = (x-4)^2 - 13 \\); the minimum is \\( -13 \\), at \\( x = 4 \\)."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:mcq:a0b18771', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'mcq', 'mcq', 1, '{"question": "Solve \\( (x+2)^2 = 9 \\).", "options": ["\\( x = 1 \\) or \\( x = -5 \\)", "\\( x = 1 \\) only", "\\( x = 7 \\) or \\( x = -7 \\)", "\\( x = 3 \\) or \\( x = -3 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( x+2 = \\pm 3 \\), so \\( x = 1 \\) or \\( x = -5 \\). You must take both signs."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:mcq:83e365d1', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'mcq', 'mcq', 1, '{"question": "Solve \\( x^2 + 4x - 1 = 0 \\), giving your answers in exact form.", "options": ["\\( x = -2 \\pm \\sqrt{5} \\)", "\\( x = -2 \\pm \\sqrt{3} \\)", "\\( x = 2 \\pm \\sqrt{5} \\)", "\\( x = -0.24 \\) or \\( x = -4.24 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( (x+2)^2 - 4 - 1 = 0 \\Rightarrow (x+2)^2 = 5 \\Rightarrow x = -2 \\pm \\sqrt{5} \\). The decimals are not ''exact''."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:mcq:904296b0', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'mcq', 'mcq', 1, '{"question": "How many real solutions does \\( 2x^2 + 3x + 5 = 0 \\) have?", "options": ["None", "One", "Two", "Infinitely many"]}'::jsonb, '{"answer": 0, "explain": "\\( b^2 - 4ac = 9 - 40 = -31 < 0 \\), so no real roots."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:mcq:1638fbd6', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'mcq', 'mcq', 1, '{"question": "Which value of \\( k \\) gives \\( x^2 + 6x + k \\) exactly one (repeated) root?", "options": ["\\( k = 9 \\)", "\\( k = 6 \\)", "\\( k = 3 \\)", "\\( k = 36 \\)"]}'::jsonb, '{"answer": 0, "explain": "One root needs \\( b^2 - 4ac = 0 \\): \\( 36 - 4k = 0 \\Rightarrow k = 9 \\)."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:mcq:c36a11b2', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'mcq', 'mcq', 1, '{"question": "In the quadratic formula, what is the discriminant?", "options": ["\\( b^2 - 4ac \\)", "\\( \\sqrt{b^2 - 4ac} \\)", "\\( -b \\pm \\sqrt{b^2 - 4ac} \\)", "\\( 2a \\)"]}'::jsonb, '{"answer": 0, "explain": "The discriminant is the part under the root, \\( b^2 - 4ac \\); its sign decides the number of real roots."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:mcq:265624d5', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'mcq', 'mcq', 1, '{"question": "A question says ''Hence solve...''. What does this instruct you to do?", "options": ["Use the result you just found (the completed-square form)", "Start again with the quadratic formula", "Give the answer as a decimal", "Draw a graph"]}'::jsonb, '{"answer": 0, "explain": "''Hence'' means build on the previous part — here, use the completed-square form, not a fresh method."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:mcq:8262c2cb', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'mcq', 'mcq', 1, '{"question": "Write \\( x^2 - 5x + 2 \\) in the form \\( (x+p)^2 + q \\).", "options": ["\\( \\left(x - \\tfrac{5}{2}\\right)^2 - \\tfrac{17}{4} \\)", "\\( \\left(x - \\tfrac{5}{2}\\right)^2 + 2 \\)", "\\( (x-5)^2 - 23 \\)", "\\( \\left(x - \\tfrac{5}{2}\\right)^2 - \\tfrac{25}{4} \\)"]}'::jsonb, '{"answer": 0, "explain": "Half of \\( -5 \\) is \\( -\\tfrac{5}{2} \\); \\( \\left(x-\\tfrac{5}{2}\\right)^2 = x^2 - 5x + \\tfrac{25}{4} \\), so subtract \\( \\tfrac{25}{4} \\) and add 2: \\( -\\tfrac{25}{4} + \\tfrac{8}{4} = -\\tfrac{17}{4} \\)."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:mcq:67172467', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'mcq', 'mcq', 1, '{"question": "The graph of \\( y = (x-3)^2 + 4 \\) has its lowest point at:", "options": ["\\( (3,\\ 4) \\)", "\\( (-3,\\ 4) \\)", "\\( (3,\\ -4) \\)", "\\( (4,\\ 3) \\)"]}'::jsonb, '{"answer": 0, "explain": "Vertex of \\( (x+p)^2 + q \\) is \\( (-p,\\ q) \\); here \\( (3,\\ 4) \\). Since \\( a>0 \\) it is a minimum."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:tf:add15775', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'tf', 'tf', 1, '{"question": "\\( x^2 + 6x - 11 \\) can be written as \\( (x+3)^2 - 20 \\)."}'::jsonb, '{"answer": true, "explain": "\\( (x+3)^2 - 20 = x^2 + 6x + 9 - 20 = x^2 + 6x - 11 \\). ✓"}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:tf:107ca7f0', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'tf', 'tf', 1, '{"question": "\\( x^2 + 8x + 1 = (x+8)^2 + 1 \\)."}'::jsonb, '{"answer": false, "explain": "You halve the 8 to get \\( (x+4)^2 \\), and \\( (x+4)^2 = x^2+8x+16 \\), so it is \\( (x+4)^2 - 15 \\)."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:tf:7e33cc5b', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'tf', 'tf', 1, '{"question": "Giving \\( x = 1.47 \\) as the answer to an ''exact'' question earns full marks."}'::jsonb, '{"answer": false, "explain": "''Exact'' requires surd/fraction form, e.g. \\( -3 + 2\\sqrt{5} \\); a decimal alone scores no marks."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:tf:21c174d5', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'tf', 'tf', 1, '{"question": "The equation \\( (x+2)^2 = 9 \\) has two solutions."}'::jsonb, '{"answer": true, "explain": "\\( x + 2 = \\pm 3 \\), giving \\( x = 1 \\) and \\( x = -5 \\)."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:tf:914b2de2', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'tf', 'tf', 1, '{"question": "If \\( b^2 - 4ac = 0 \\) the quadratic has no real roots."}'::jsonb, '{"answer": false, "explain": "\\( b^2 - 4ac = 0 \\) gives exactly one (repeated) real root; \\( < 0 \\) gives none."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:tf:e9991ac0', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'tf', 'tf', 1, '{"question": "To complete the square on \\( 2x^2 + 8x + 3 \\) you first factor 2 from all three terms."}'::jsonb, '{"answer": false, "explain": "Factor 2 from the first two terms only: \\( 2(x^2 + 4x) + 3 \\); the constant stays outside."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:tf:91c93f3a', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'tf', 'tf', 1, '{"question": "The minimum value of \\( (x-4)^2 + 7 \\) is 7."}'::jsonb, '{"answer": true, "explain": "A square is never negative, so the smallest value is \\( 0 + 7 = 7 \\), at \\( x = 4 \\)."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:tf:ca3ce828', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'tf', 'tf', 1, '{"question": "The quadratic formula is printed on the exam formula sheet, so you need not memorise it."}'::jsonb, '{"answer": false, "explain": "The quadratic formula is a MUST-MEMORISE formula in 6993; only the binomial series, binomial distribution, trapezium rule and kinematics relations are provided."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:learn:43d83f34', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'learn', 'mcq', 1, '{"readingTitle": "What does ''completing the square'' mean?", "reading": "<p><strong>Completing the square</strong> rewrites a quadratic \\( ax^2 + bx + c \\) in the form \\[ a(x + p)^2 + q. \\] The quadratic is unchanged — only its <em>shape</em> is now visible.</p>\n            <ul>\n              <li>It reveals the <strong>turning point</strong> (vertex) of the parabola: for \\( a(x + p)^2 + q \\) the vertex is at \\( (-p,\\ q) \\).</li>\n              <li>It lets you solve \\( ax^2 + bx + c = 0 \\) in <strong>exact form</strong> (surds), not just as a decimal.</li>\n              <li>It gives the <strong>minimum</strong> (if \\( a > 0 \\)) or <strong>maximum</strong> (if \\( a < 0 \\)) value of the quadratic — that value is \\( q \\).</li>\n            </ul>\n            <p>In this qualification you must be fluent with the general case \\( a \\ne 1 \\), which is beyond most GCSE work.</p>", "question": "For \\( 2(x-3)^2 + 5 \\), where is the turning point?", "options": ["\\( (3,\\ 5) \\)", "\\( (-3,\\ 5) \\)", "\\( (3,\\ -5) \\)", "\\( (5,\\ 3) \\)"]}'::jsonb, '{"answer": 0, "explain": "The vertex of \\( a(x+p)^2+q \\) is at \\( (-p,\\ q) \\); here \\( p=-3,\\ q=5 \\), so \\( (3,\\ 5) \\)."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:learn:9f1aecc2', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'learn', 'mcq', 1, '{"readingTitle": "How do you complete the square when a = 1?", "reading": "<p>For \\( x^2 + bx + c \\): halve the coefficient of \\( x \\), square it, and adjust.</p>\n            <p><strong>Worked example — \\( x^2 + 6x - 11 \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Half of \\( 6 \\) is \\( 3 \\), so start with \\( (x + 3)^2 \\).</td></tr>\n              <tr><td>2. But \\( (x + 3)^2 = x^2 + 6x + 9 \\) — that is \\( 9 \\) too big.</td></tr>\n              <tr><td>3. Subtract \\( 9 \\), then include the \\( -11 \\): \\( (x + 3)^2 - 9 - 11 \\).</td></tr>\n              <tr><td>4. So \\[ x^2 + 6x - 11 = (x + 3)^2 - 20. \\]</td></tr>\n            </table>\n            <p>Check by expanding: \\( (x+3)^2 - 20 = x^2 + 6x + 9 - 20 = x^2 + 6x - 11 \\). ✓</p>", "question": "Complete the square: \\( x^2 + 8x + 3 \\).", "options": ["\\( (x+4)^2 - 13 \\)", "\\( (x+4)^2 + 3 \\)", "\\( (x+8)^2 - 13 \\)", "\\( (x+4)^2 - 19 \\)"]}'::jsonb, '{"answer": 0, "explain": "Half of 8 is 4; \\( (x+4)^2 = x^2+8x+16 \\), which is 16 too big, so \\( (x+4)^2 - 16 + 3 = (x+4)^2 - 13 \\)."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:learn:c89aa217', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'learn', 'mcq', 1, '{"readingTitle": "How do you complete the square when a ≠ 1?", "reading": "<p>Factor the \\( a \\) out of the first two terms first, complete the square inside, then multiply back.</p>\n            <p><strong>Worked example — \\( 2x^2 + 12x + 5 \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Factor 2 from the \\( x \\)-terms: \\( 2\\big(x^2 + 6x\\big) + 5 \\).</td></tr>\n              <tr><td>2. Complete the square inside: \\( x^2 + 6x = (x+3)^2 - 9 \\).</td></tr>\n              <tr><td>3. Substitute: \\( 2\\big[(x+3)^2 - 9\\big] + 5 \\).</td></tr>\n              <tr><td>4. Expand the bracket: \\( 2(x+3)^2 - 18 + 5 = 2(x+3)^2 - 13 \\).</td></tr>\n            </table>\n            <p>So \\[ 2x^2 + 12x + 5 = 2(x + 3)^2 - 13. \\] The minimum value is \\( -13 \\), at \\( x = -3 \\).</p>", "question": "Which is the correct first step for \\( 3x^2 + 12x + 1 \\)?", "options": ["\\( 3(x^2 + 4x) + 1 \\)", "\\( 3(x^2 + 12x) + 1 \\)", "\\( (3x + 2)^2 + 1 \\)", "\\( 3(x^2 + 4x + 1) \\)"]}'::jsonb, '{"answer": 0, "explain": "Factor \\( a=3 \\) from the first two terms only: \\( 3(x^2 + 4x) + 1 \\). The constant stays outside."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:learn:af2727c7', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'learn', 'mcq', 1, '{"readingTitle": "How do you solve a quadratic in exact form?", "reading": "<p>Once a quadratic is in completed-square form, solving it needs only a rearrange and a square root — and it naturally gives an <strong>exact</strong> (surd) answer.</p>\n            <p><strong>Worked example — solve \\( x^2 + 6x - 11 = 0 \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. From above: \\( (x + 3)^2 - 20 = 0 \\).</td></tr>\n              <tr><td>2. Rearrange: \\( (x + 3)^2 = 20 \\).</td></tr>\n              <tr><td>3. Square root <em>both</em> signs: \\( x + 3 = \\pm\\sqrt{20} = \\pm 2\\sqrt{5} \\).</td></tr>\n              <tr><td>4. So \\[ x = -3 \\pm 2\\sqrt{5}. \\]</td></tr>\n            </table>\n            <p><strong>\"Exact\" is a command word.</strong> \\( x = -3 \\pm 2\\sqrt{5} \\) is exact; \\( x = 1.47 \\) or \\( x = -7.47 \\) is <em>not</em> and scores no marks on an \"exact\" question. Writing both the exact and the decimal form is safe.</p>", "question": "Solve \\( (x - 4)^2 = 12 \\), giving exact answers.", "options": ["\\( x = 4 \\pm 2\\sqrt{3} \\)", "\\( x = 4 \\pm \\sqrt{12} \\) only as a decimal", "\\( x = 4 + 2\\sqrt{3} \\)", "\\( x = -4 \\pm 2\\sqrt{3} \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( x - 4 = \\pm\\sqrt{12} = \\pm 2\\sqrt{3} \\), so \\( x = 4 \\pm 2\\sqrt{3} \\) — both roots, simplified surd."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:learn:259a652a', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'learn', 'mcq', 1, '{"readingTitle": "When should you use the quadratic formula?", "reading": "<p>The <strong>quadratic formula</strong> solves \\( ax^2 + bx + c = 0 \\): \\[ x = \\frac{-b \\pm \\sqrt{b^2 - 4ac}}{2a}. \\] You must <strong>memorise</strong> it — it is not on the formula sheet.</p>\n            <ul>\n              <li>Use it (or completing the square) when a quadratic does not factorise nicely.</li>\n              <li>The <strong>discriminant</strong> \\( b^2 - 4ac \\) tells you how many real roots there are: \\( > 0 \\) two, \\( = 0 \\) one (repeated), \\( < 0 \\) none.</li>\n              <li>If the question says <em>\"Hence\"</em>, use the completed-square form you just found — do <strong>not</strong> restart with the formula.</li>\n            </ul>\n            <p>For an \"exact\" answer, leave the surd: e.g. \\( x = \\dfrac{-5 \\pm \\sqrt{13}}{2} \\), not a rounded decimal.</p>", "question": "How many real roots does \\( x^2 - 4x + 7 = 0 \\) have?", "options": ["None", "One", "Two", "Cannot tell"]}'::jsonb, '{"answer": 0, "explain": "\\( b^2 - 4ac = 16 - 28 = -12 < 0 \\), so there are no real roots."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:misc:4cac0551', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \\( x^2 + 6x - 11 = (x+6)^2 - 11 \\)</p><p><strong>✅ The correct idea:</strong> You must HALVE the coefficient of \\( x \\): it is \\( (x+3)^2 \\), not \\( (x+6)^2 \\). A weak answer copies the 6; a strong answer writes \\( (x+3)^2 - 9 - 11 = (x+3)^2 - 20 \\).</p>", "question": "Complete the square: \\( x^2 + 6x - 11 \\).", "options": ["\\( (x+3)^2 - 20 \\)", "\\( (x+6)^2 - 11 \\)", "\\( (x+3)^2 - 11 \\)", "\\( (x+6)^2 - 47 \\)"]}'::jsonb, '{"answer": 0, "explain": "Halve 6 to get 3; \\( (x+3)^2 = x^2+6x+9 \\), so \\( (x+3)^2 - 9 - 11 = (x+3)^2 - 20 \\)."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:misc:7d747242', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Solving \\( (x+3)^2 = 20 \\) gives \\( x + 3 = \\sqrt{20} \\) only</p><p><strong>✅ The correct idea:</strong> Taking a square root gives \\( \\pm \\). A weak answer keeps one root; a strong answer writes \\( x + 3 = \\pm 2\\sqrt{5} \\), so \\( x = -3 \\pm 2\\sqrt{5} \\) — two roots.</p>", "question": "\\( (x+3)^2 = 20 \\). What is \\( x \\)?", "options": ["\\( -3 \\pm 2\\sqrt{5} \\)", "\\( -3 + 2\\sqrt{5} \\)", "\\( 3 \\pm 2\\sqrt{5} \\)", "\\( -3 \\pm \\sqrt{20} \\) as a decimal"]}'::jsonb, '{"answer": 0, "explain": "\\( x + 3 = \\pm 2\\sqrt{5} \\), so \\( x = -3 \\pm 2\\sqrt{5} \\)."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:misc:2c4f0c75', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Writing the answer to an ''exact'' question as \\( -7.47 \\) and \\( 1.47 \\)</p><p><strong>✅ The correct idea:</strong> ''Exact'' means surds/fractions kept, not decimals. A weak answer rounds; a strong answer gives \\( -3 \\pm 2\\sqrt{5} \\) (and may add the decimals as a check).</p>", "question": "Which is an ''exact'' answer?", "options": ["\\( -3 + 2\\sqrt{5} \\)", "\\( 1.47 \\)", "\\( 1.5 \\)", "about \\( 1.47 \\)"]}'::jsonb, '{"answer": 0, "explain": "Only the surd form \\( -3 + 2\\sqrt{5} \\) is exact."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:misc:07923fc1', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For \\( 2x^2 + 12x + 5 \\), factoring gives \\( 2(x^2 + 6x + 5) \\)</p><p><strong>✅ The correct idea:</strong> Only the \\( x \\)-terms are factored: \\( 2(x^2 + 6x) + 5 \\). A weak answer drags the constant inside; a strong answer keeps \\( +5 \\) outside and finishes \\( 2(x+3)^2 - 13 \\).</p>", "question": "Correct factor step for \\( 2x^2 + 12x + 5 \\)?", "options": ["\\( 2(x^2 + 6x) + 5 \\)", "\\( 2(x^2 + 6x + 5) \\)", "\\( 2(x^2 + 12x) + 5 \\)", "\\( (2x + 6)^2 + 5 \\)"]}'::jsonb, '{"answer": 0, "explain": "Factor 2 from the first two terms only, leaving \\( +5 \\) outside."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:misc:0eacccf9', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \\( x^2 - 4x + 9 = 0 \\) must have solutions because it is a quadratic</p><p><strong>✅ The correct idea:</strong> Not every quadratic has real roots. A weak answer assumes two roots; a strong answer checks the discriminant: \\( 16 - 36 = -20 < 0 \\), so there are no real roots.</p>", "question": "How many real roots has \\( x^2 - 4x + 9 = 0 \\)?", "options": ["None", "One", "Two", "Three"]}'::jsonb, '{"answer": 0, "explain": "\\( b^2 - 4ac = 16 - 36 = -20 < 0 \\Rightarrow \\) no real roots."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:tips:03dda54c', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'tips', 'mcq', 1, '{"readingTitle": "explain — The ''exact'' command word", "reading": "<p><strong>0 marks:</strong> \\( x = 1.47,\\ -7.47 \\) on an \"exact\" question — decimals only.</p><p><strong>Full marks:</strong> \\( x = -3 \\pm 2\\sqrt{5} \\). If unsure, write the exact form <em>and</em> the decimal — the exact form earns the marks and the decimal never loses them.</p>", "question": "On an ''exact'' question, which is safest?", "options": ["Give the surd form (optionally with the decimal)", "Give only the decimal", "Round to 2 d.p.", "Give only the decimal to 3 s.f."]}'::jsonb, '{"answer": 0, "explain": "The exact surd form is required; adding the decimal is harmless."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:tips:13941a0e', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'tips', 'mcq', 1, '{"readingTitle": "tip — Show every step (method marks)", "reading": "<p>For \"complete the square\" [3]: examiners award <strong>B1</strong> for \\( (x+3)^2 \\), <strong>M1</strong> for adjusting the constant, <strong>A1</strong> for the final \\( (x+3)^2 - 20 \\). Write each line so a slip costs one mark, not all three.</p>", "question": "Why write out each line of working?", "options": ["To earn method marks even if the final answer slips", "It is not necessary", "To use more paper", "To slow down"]}'::jsonb, '{"answer": 0, "explain": "Method (M) and intermediate (B/A) marks are awarded for visible correct steps."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:tips:585f1b7d', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'tips', 'mcq', 1, '{"readingTitle": "explain — ''Hence'' means reuse part (a)", "reading": "<p>If part (b) says \"<em>Hence</em> solve \\( \\text{f}(x) = 0 \\)\", start from your completed-square form \\( (x+3)^2 - 20 = 0 \\) — do <strong>not</strong> reach for the quadratic formula. The 2024 examiners noted candidates who restarted (or converted back to the original) wasted time and risked errors.</p>", "question": "Part (b) says ''Hence solve''. You should:", "options": ["Use your part (a) completed-square form", "Use the quadratic formula from scratch", "Factorise by trial", "Draw a graph and read off"]}'::jsonb, '{"answer": 0, "explain": "''Hence'' directs you to build on part (a)."}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:fib:2e2f9ec8', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'fib', 'fib', 2, '{"question": "In the quadratic formula \\( x = \\frac{-b \\pm \\sqrt{b^2 - 4ac}}{2a} \\), the term before the \\( \\pm \\) sign is ___B1___ and the denominator is ___B2___.", "blankOptions": {"B1": ["square", "-b", "negative", "double"], "B2": ["add", "square", "both", "2a"]}}'::jsonb, '{"blanks": {"B1": "-b", "B2": "2a"}}'::jsonb),
