('additional-maths:1-3-quadratics-and-completing-the-square:fib:3e868d82', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'fib', 'fib', 2, '{"question": "To complete the square on \\( x^2 + 6x - 11 \\), the number inside the bracket \\( (x + a)^2 \\) is ___B1___ and the number subtracted at the end is ___B2___.", "blankOptions": {"B1": ["exact", "3", "half", "q"], "B2": ["square", "half", "q", "20"]}}'::jsonb, '{"blanks": {"B1": "3", "B2": "20"}}'::jsonb),
