('additional-maths:1-3-quadratics-and-completing-the-square:match:1d97ca2b', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Discriminant \\( < 0 \\)”?", "options": ["\\( (x-5)^2 - 25 \\)", "No real roots", "\\( (x+1)^2 - 6 \\)", "Left in surd/fraction form, not a decimal"]}'::jsonb, '{"answer": 1, "explain": "“Discriminant \\( < 0 \\)” means: No real roots"}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:match:093e6623', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Quadratic formula”?", "options": ["\\( (x+1)^2 - 6 \\)", "Two distinct real roots", "One repeated real root", "\\( x = \\frac{-b \\pm \\sqrt{b^2 - 4ac}}{2a} \\)"]}'::jsonb, '{"answer": 3, "explain": "“Quadratic formula” means: \\( x = \\frac{-b \\pm \\sqrt{b^2 - 4ac}}{2a} \\)"}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:match:52565676', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Vertex of \\( a(x+p)^2 + q \\)”?", "options": ["One repeated real root", "\\( (-p,\\ q) \\)", "\\( (x+1)^2 - 6 \\)", "\\( x = \\frac{-b \\pm \\sqrt{b^2 - 4ac}}{2a} \\)"]}'::jsonb, '{"answer": 1, "explain": "“Vertex of \\( a(x+p)^2 + q \\)” means: \\( (-p,\\ q) \\)"}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:match:1ccc50a5', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Minimum value of \\( a(x+p)^2 + q \\) when \\( a>0 \\)”?", "options": ["Left in surd/fraction form, not a decimal", "\\( (x-2)^2 - 3 \\)", "\\( (x-5)^2 - 25 \\)", "\\( q \\)"]}'::jsonb, '{"answer": 3, "explain": "“Minimum value of \\( a(x+p)^2 + q \\) when \\( a>0 \\)” means: \\( q \\)"}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:match:014314d2', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “''Exact'' answer”?", "options": ["\\( (x-5)^2 - 25 \\)", "No real roots", "Left in surd/fraction form, not a decimal", "Use the result from part (a)"]}'::jsonb, '{"answer": 2, "explain": "“''Exact'' answer” means: Left in surd/fraction form, not a decimal"}'::jsonb),
('additional-maths:1-3-quadratics-and-completing-the-square:match:26cf3e95', 'additional-maths', 'additional-maths:1-3-quadratics-and-completing-the-square', '1.3 Quadratics and Completing the Square', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “''Hence'' in part (b)”?", "options": ["Left in surd/fraction form, not a decimal", "No real roots", "\\( q \\)", "Use the result from part (a)"]}'::jsonb, '{"answer": 3, "explain": "“''Hence'' in part (b)” means: Use the result from part (a)"}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:mcq:d2086de5', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'mcq', 'mcq', 1, '{"question": "Solve \\( 3x - 5 < 7 \\).", "options": ["\\( x > 4 \\)", "\\( x < 4 \\)", "\\( x < 12 \\)", "\\( x < 2 \\)"]}'::jsonb, '{"answer": 1, "explain": "Add 5: \\( 3x < 12 \\); divide by 3 (positive, no flip): \\( x < 4 \\)."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:mcq:026bfd12', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'mcq', 'mcq', 1, '{"question": "Solve \\( -2x > 8 \\).", "options": ["\\( x > -4 \\)", "\\( x > 4 \\)", "\\( x < -4 \\)", "\\( x < 4 \\)"]}'::jsonb, '{"answer": 2, "explain": "Divide by \\( -2 \\); dividing by a negative flips the sign, giving \\( x < -4 \\)."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:mcq:b15debdb', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'mcq', 'mcq', 1, '{"question": "Solve \\( 5 - 2x \\ge 11 \\).", "options": ["\\( x \\le -3 \\)", "\\( x \\ge -3 \\)", "\\( x \\le 3 \\)", "\\( x \\ge 3 \\)"]}'::jsonb, '{"answer": 0, "explain": "Subtract 5: \\( -2x \\ge 6 \\); divide by \\( -2 \\) and flip: \\( x \\le -3 \\)."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:mcq:c5f566e0', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'mcq', 'mcq', 1, '{"question": "Solve the double inequality \\( \\frac{1}{3} < \\frac{2x-1}{5} < 1 \\).", "options": ["\\( \\frac{4}{3} < x < 3 \\)", "\\( \\frac{2}{3} < x < 3 \\)", "\\( \\frac{4}{3} < x < 2 \\)", "\\( 1 < x < 3 \\)"]}'::jsonb, '{"answer": 0, "explain": "Multiply all three parts by 5: \\( \\frac{5}{3} < 2x-1 < 5 \\); add 1: \\( \\frac{8}{3} < 2x < 6 \\); divide by 2: \\( \\frac{4}{3} < x < 3 \\)."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:mcq:c87798f9', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'mcq', 'mcq', 1, '{"question": "Solve \\( -4 < 3x + 2 \\le 11 \\).", "options": ["\\( -2 < x \\le 3 \\)", "\\( -2 \\le x < 3 \\)", "\\( 2 < x \\le 3 \\)", "\\( -6 < x \\le 9 \\)"]}'::jsonb, '{"answer": 0, "explain": "Subtract 2 from all parts: \\( -6 < 3x \\le 9 \\); divide by 3: \\( -2 < x \\le 3 \\). Option D forgot to divide by 3."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:mcq:7c844b03', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'mcq', 'mcq', 1, '{"question": "Solve \\( x^2 - x - 6 > 0 \\).", "options": ["\\( -2 < x < 3 \\)", "\\( x < -2 \\) or \\( x > 3 \\)", "\\( x < -3 \\) or \\( x > 2 \\)", "\\( x > 3 \\) only"]}'::jsonb, '{"answer": 1, "explain": "\\( (x-3)(x+2) > 0 \\); the upward parabola is above the axis outside its roots, so \\( x < -2 \\) or \\( x > 3 \\)."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:mcq:6591c032', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'mcq', 'mcq', 1, '{"question": "Solve \\( x^2 - x - 6 \\le 0 \\).", "options": ["\\( x \\le -2 \\) or \\( x \\ge 3 \\)", "\\( -3 \\le x \\le 2 \\)", "\\( -2 \\le x \\le 3 \\)", "\\( 2 \\le x \\le 3 \\)"]}'::jsonb, '{"answer": 2, "explain": "\\( \\le 0 \\) is the region on or below the axis, between the roots: \\( -2 \\le x \\le 3 \\)."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:mcq:ec713b04', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'mcq', 'mcq', 1, '{"question": "Solve \\( x^2 > 9 \\).", "options": ["\\( x > 3 \\)", "\\( x < -3 \\) or \\( x > 3 \\)", "\\( -3 < x < 3 \\)", "\\( x > 3 \\) or \\( x > -3 \\)"]}'::jsonb, '{"answer": 1, "explain": "\\( x^2 - 9 > 0 \\Rightarrow (x-3)(x+3) > 0 \\); outside the roots: \\( x < -3 \\) or \\( x > 3 \\). Writing just \\( x > 3 \\) misses the negative arm."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:mcq:c943fc61', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'mcq', 'mcq', 1, '{"question": "Solve \\( x^2 \\le 16 \\).", "options": ["\\( -4 \\le x \\le 4 \\)", "\\( x \\le 4 \\)", "\\( x \\le -4 \\) or \\( x \\ge 4 \\)", "\\( 0 \\le x \\le 4 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( x^2 - 16 \\le 0 \\Rightarrow (x-4)(x+4) \\le 0 \\); the region between the roots (inclusive) is \\( -4 \\le x \\le 4 \\)."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:mcq:fa697feb', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'mcq', 'mcq', 1, '{"question": "The critical values for \\( x^2 + 2x - 15 \\ge 0 \\) are:", "options": ["\\( x = 5 \\) and \\( x = -3 \\)", "\\( x = -5 \\) and \\( x = 3 \\)", "\\( x = 15 \\) and \\( x = 1 \\)", "\\( x = -2 \\) and \\( x = 15 \\)"]}'::jsonb, '{"answer": 1, "explain": "\\( x^2 + 2x - 15 = (x+5)(x-3) \\), so the roots (critical values) are \\( x = -5 \\) and \\( x = 3 \\)."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:mcq:f765cb88', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'mcq', 'mcq', 1, '{"question": "On a number line, the solution \\( -1 \\le x < 4 \\) is drawn with:", "options": ["an open circle at \\( -1 \\) and a closed circle at \\( 4 \\)", "a closed circle at \\( -1 \\) and an open circle at \\( 4 \\)", "closed circles at both ends", "open circles at both ends"]}'::jsonb, '{"answer": 1, "explain": "\\( \\le \\) at \\( -1 \\) means it is included (closed); \\( < \\) at \\( 4 \\) means it is excluded (open)."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:mcq:ab9fb7bb', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'mcq', 'mcq', 1, '{"question": "A rectangle has width \\( x \\) cm and area \\( x(x+2) \\) cm², which must be less than 15 cm². For what widths does this hold?", "options": ["\\( 0 < x < 3 \\)", "\\( -5 < x < 3 \\)", "\\( x < 3 \\)", "\\( x > 3 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( x^2 + 2x - 15 < 0 \\Rightarrow (x+5)(x-3) < 0 \\Rightarrow -5 < x < 3 \\); but a width must be positive, so \\( 0 < x < 3 \\)."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:tf:984dd56c', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'tf', 'tf', 1, '{"question": "Multiplying or dividing both sides of an inequality by a negative number reverses the inequality sign."}'::jsonb, '{"answer": true, "explain": "Correct — e.g. from \\( 2 < 5 \\), multiplying by \\( -1 \\) gives \\( -2 > -5 \\); the order reverses."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:tf:429f90ce', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'tf', 'tf', 1, '{"question": "\\( -x > 6 \\) is the same as \\( x > -6 \\)."}'::jsonb, '{"answer": false, "explain": "Dividing \\( -x > 6 \\) by \\( -1 \\) flips the sign, giving \\( x < -6 \\), not \\( x > -6 \\). This is the classic 2024 Q1 error."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:tf:23659c28', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'tf', 'tf', 1, '{"question": "To solve \\( \\frac{1}{3} < \\frac{2x-1}{5} < 1 \\) you may operate on all three parts at once."}'::jsonb, '{"answer": true, "explain": "Yes — whatever you do (×5, +1, ÷2) you do to every part of the sandwich inequality."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:tf:4d276fee', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'tf', 'tf', 1, '{"question": "The inequality \\( x^2 > 9 \\) has solution \\( x > 3 \\) only."}'::jsonb, '{"answer": false, "explain": "It is \\( (x-3)(x+3) > 0 \\Rightarrow x < -3 \\) or \\( x > 3 \\); a negative such as \\( -5 \\) also satisfies it."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:tf:c7b39e3e', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'tf', 'tf', 1, '{"question": "For \\( x^2 - x - 6 < 0 \\), because the parabola opens upwards the solution lies between the roots."}'::jsonb, '{"answer": true, "explain": "An upward parabola is below the axis (\\( y < 0 \\)) between its roots, so \\( -2 < x < 3 \\)."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:tf:396c6207', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'tf', 'tf', 1, '{"question": "A closed (filled) circle on a number line shows that the end value is included (\\( \\le \\) or \\( \\ge \\))."}'::jsonb, '{"answer": true, "explain": "Correct; an open circle is used for strict inequalities (\\( < \\) or \\( > \\)) where the end value is excluded."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:tf:0bba18fc', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'tf', 'tf', 1, '{"question": "Adding the same number to both sides of an inequality can change the direction of the sign."}'::jsonb, '{"answer": false, "explain": "Only multiplying/dividing by a negative flips the sign; adding or subtracting never does."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:tf:d0efb92d', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'tf', 'tf', 1, '{"question": "Multiplying the double inequality \\( -1 < x < 4 \\) by \\( -2 \\) gives \\( -8 < -2x < 2 \\)."}'::jsonb, '{"answer": true, "explain": "Multiplying by \\( -2 \\) and flipping both signs gives \\( 2 > -2x > -8 \\), which is the same as \\( -8 < -2x < 2 \\)."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:learn:aeeca082', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'learn', 'mcq', 1, '{"readingTitle": "What does it mean to solve an inequality?", "reading": "<p>An <strong>inequality</strong> compares two expressions with \\( < \\) (less than), \\( > \\) (greater than), \\( \\le \\) (less than or equal to) or \\( \\ge \\) (greater than or equal to). Solving one means finding <strong>every</strong> value of the variable that makes it true — usually a <strong>range</strong> of values, not a single number.</p>\n            <ul>\n              <li>The answer is a <strong>solution set</strong>, e.g. \\( x < 4 \\) or \\( -2 \\le x \\le 3 \\).</li>\n              <li><strong>Strict</strong> inequalities (\\( < \\), \\( > \\)) exclude the end value; <strong>non-strict</strong> ones (\\( \\le \\), \\( \\ge \\)) include it.</li>\n              <li>You can picture a solution set on a <strong>number line</strong> — an <strong>open</strong> circle for a value that is excluded, a <strong>closed</strong> (filled) circle for one that is included.</li>\n            </ul>\n            <p>Most of the algebra you already use for equations works for inequalities too — with <strong>one crucial exception</strong> that costs marks every year (next card).</p>", "question": "Which describes the solution set \\( -2 \\le x \\le 3 \\)?", "options": ["Every \\( x \\) from \\( -2 \\) to \\( 3 \\), both ends included", "Only \\( x = -2 \\) and \\( x = 3 \\)", "Every \\( x \\) from \\( -2 \\) to \\( 3 \\), both ends excluded", "Only whole numbers between \\( -2 \\) and \\( 3 \\)"]}'::jsonb, '{"answer": 0, "explain": "The \\( \\le \\) signs are non-strict, so both \\( -2 \\) and \\( 3 \\) are included, along with every real number between them."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:learn:c619e2fe', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'learn', 'mcq', 1, '{"readingTitle": "When you manipulate an inequality, when does the sign flip?", "reading": "<p>You may do the same thing to <strong>both sides</strong> of an inequality — but watch the sign:</p>\n            <ul>\n              <li><strong>Add or subtract</strong> any number: the sign <strong>never</strong> changes.</li>\n              <li><strong>Multiply or divide by a positive</strong> number: the sign <strong>never</strong> changes.</li>\n              <li><strong>Multiply or divide by a negative</strong> number: you <strong>must reverse (flip) the inequality sign.</strong></li>\n            </ul>\n            <p>Why? Because \\( 2 < 5 \\) is true, but multiplying by \\( -1 \\) gives \\( -2 \\) and \\( -5 \\), and \\( -2 > -5 \\) — the order reverses.</p>\n            <p><strong>Worked example — solve \\( 5 - 2x \\ge 11 \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Subtract 5 from both sides: \\( -2x \\ge 6 \\).</td></tr>\n              <tr><td>2. Divide both sides by \\( -2 \\) — this is division by a <em>negative</em>, so FLIP the sign: \\( x \\le -3 \\).</td></tr>\n            </table>\n            <p>Check with \\( x = -4 \\): \\( 5 - 2(-4) = 13 \\ge 11 \\) ✓. The <strong>#1 examiner-reported error</strong> is reaching \\( -x > 6 \\) and writing \\( x > -6 \\) instead of \\( x < -6 \\).</p>", "question": "Solve \\( -3x > 12 \\).", "options": ["\\( x > 4 \\)", "\\( x < -4 \\)", "\\( x > -4 \\)", "\\( x < 4 \\)"]}'::jsonb, '{"answer": 1, "explain": "Divide both sides by \\( -3 \\); because \\( -3 \\) is negative, the sign flips, giving \\( x < -4 \\)."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:learn:b385b6bc', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'learn', 'mcq', 1, '{"readingTitle": "How do you solve a double (''sandwich'') inequality?", "reading": "<p>A <strong>double</strong> (or \"sandwich\") inequality such as \\( \\frac{1}{3} < \\frac{2x-1}{5} < 1 \\) traps one expression between two bounds. The rule is simple: whatever you do, <strong>do it to all three parts at once.</strong></p>\n            <p><strong>Worked example — solve \\( \\frac{1}{3} < \\frac{2x-1}{5} < 1 \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Multiply <em>all three</em> parts by 5: \\( \\frac{5}{3} < 2x - 1 < 5 \\).</td></tr>\n              <tr><td>2. Add 1 to all three parts: \\( \\frac{8}{3} < 2x < 6 \\).</td></tr>\n              <tr><td>3. Divide all three parts by 2: \\( \\frac{4}{3} < x < 3 \\).</td></tr>\n            </table>\n            <p>So the solution is \\( \\frac{4}{3} < x < 3 \\). If you ever multiply or divide the parts by a negative, flip <strong>both</strong> signs and rewrite the chain in ascending order. Taking the two inequalities separately is fine too — just recombine the answers at the end.</p>", "question": "Solve \\( -1 < 2x + 3 < 9 \\).", "options": ["\\( -2 < x < 3 \\)", "\\( -1 < x < 9 \\)", "\\( -2 < x < 6 \\)", "\\( 1 < x < 3 \\)"]}'::jsonb, '{"answer": 0, "explain": "Subtract 3 from all three parts: \\( -4 < 2x < 6 \\); divide all three by 2: \\( -2 < x < 3 \\)."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:learn:7c844b03', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'learn', 'mcq', 1, '{"readingTitle": "How do you solve a quadratic inequality algebraically?", "reading": "<p>A <strong>quadratic inequality</strong> such as \\( x^2 - x - 6 > 0 \\) is solved in four steps:</p>\n            <table class=\"worked\">\n              <tr><td>1. Rearrange so one side is <strong>0</strong> (here it already is).</td></tr>\n              <tr><td>2. <strong>Factorise</strong>: \\( x^2 - x - 6 = (x - 3)(x + 2) \\).</td></tr>\n              <tr><td>3. Find the <strong>critical values</strong> — the roots where the quadratic \\( = 0 \\): \\( x = 3 \\) and \\( x = -2 \\).</td></tr>\n              <tr><td>4. Decide which region satisfies the inequality (sketch the parabola — next card).</td></tr>\n            </table>\n            <p>The graph of \\( y = x^2 - x - 6 \\) is a parabola opening <strong>upwards</strong> (because the \\( x^2 \\) coefficient is positive). It is <strong>above</strong> the \\( x \\)-axis (\\( y > 0 \\)) <em>outside</em> the roots, and <strong>below</strong> it (\\( y < 0 \\)) <em>between</em> the roots. So:</p>\n            <ul>\n              <li>\\( x^2 - x - 6 > 0 \\Rightarrow x < -2 \\ \\) or \\( \\ x > 3 \\).</li>\n              <li>\\( x^2 - x - 6 < 0 \\Rightarrow -2 < x < 3 \\).</li>\n            </ul>\n            <p><strong>Never</strong> just \"square-root and solve like an equation\" — a quadratic inequality almost always has a two-part answer.</p>", "question": "Solve \\( x^2 - x - 6 > 0 \\).", "options": ["\\( -2 < x < 3 \\)", "\\( x < -2 \\) or \\( x > 3 \\)", "\\( x < -3 \\) or \\( x > 2 \\)", "\\( x > 3 \\) only"]}'::jsonb, '{"answer": 1, "explain": "The upward parabola is above the axis outside its roots \\( -2 \\) and \\( 3 \\), so \\( x < -2 \\) or \\( x > 3 \\)."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:learn:f3c649c7', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'learn', 'mcq', 1, '{"readingTitle": "How do you read the region off a sketch of the parabola?", "reading": "<p>The safest way to get the region right is to <strong>sketch the parabola and see where it is above or below the \\( x \\)-axis.</strong> You only need a rough sketch showing which way it opens and where it crosses the axis (the critical values).</p>\n            <p>For \\( y = x^2 - x - 6 = (x-3)(x+2) \\), the curve opens upwards and crosses at \\( x = -2 \\) and \\( x = 3 \\):</p>\n            <svg viewBox=\"0 0 300 190\" width=\"100%\" style=\"max-width:340px;height:auto;display:block;margin:14px auto\" role=\"img\" aria-label=\"Upward parabola crossing the x-axis at minus 2 and 3, dipping below the axis between them\">\n              <line x1=\"20\" y1=\"120\" x2=\"285\" y2=\"120\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n              <polygon points=\"285,120 276,116 276,124\" fill=\"currentColor\"/>\n              <line x1=\"110\" y1=\"120\" x2=\"190\" y2=\"120\" stroke=\"currentColor\" stroke-width=\"6\" stroke-opacity=\"0.35\"/>\n              <path d=\"M 55,25 Q 150,255 245,25\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.5\"/>\n              <circle cx=\"110\" cy=\"120\" r=\"4\" fill=\"currentColor\"/>\n              <circle cx=\"190\" cy=\"120\" r=\"4\" fill=\"currentColor\"/>\n              <text x=\"110\" y=\"140\" text-anchor=\"middle\" font-size=\"14\" fill=\"currentColor\">-2</text>\n              <text x=\"190\" y=\"140\" text-anchor=\"middle\" font-size=\"14\" fill=\"currentColor\">3</text>\n              <text x=\"278\" y=\"112\" text-anchor=\"end\" font-size=\"13\" fill=\"currentColor\">x</text>\n            </svg>\n            <ul>\n              <li>Want \\( y < 0 \\) (curve <strong>below</strong> the axis, shaded)? Read off the region <em>between</em> the roots: \\( -2 < x < 3 \\).</li>\n              <li>Want \\( y > 0 \\) (curve <strong>above</strong> the axis)? Read off the two \"arms\" <em>outside</em> the roots: \\( x < -2 \\) or \\( x > 3 \\).</li>\n            </ul>\n            <p>If the parabola opened downwards (negative \\( x^2 \\) coefficient), the \"above/below\" regions simply swap.</p>", "question": "Using the sketch, solve \\( x^2 - x - 6 \\le 0 \\).", "options": ["\\( x \\le -2 \\) or \\( x \\ge 3 \\)", "\\( -2 \\le x \\le 3 \\)", "\\( -3 \\le x \\le 2 \\)", "\\( x \\le 3 \\)"]}'::jsonb, '{"answer": 1, "explain": "\\( \\le 0 \\) means on or below the axis — the region between (and including) the roots: \\( -2 \\le x \\le 3 \\)."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:learn:6ba07372', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'learn', 'mcq', 1, '{"readingTitle": "Why is \\( x^2 > 9 \\) not just \\( x > 3 \\)?", "reading": "<p>A very common slip is to \"square-root both sides\" of \\( x^2 > 9 \\) and write \\( x > 3 \\). That misses <strong>half</strong> the answer, because a negative number can also have a large square: \\( (-5)^2 = 25 > 9 \\).</p>\n            <p>Treat it as a <strong>quadratic inequality</strong>:</p>\n            <table class=\"worked\">\n              <tr><td>1. Rearrange to one side: \\( x^2 - 9 > 0 \\).</td></tr>\n              <tr><td>2. Factorise (difference of two squares): \\( (x - 3)(x + 3) > 0 \\).</td></tr>\n              <tr><td>3. Critical values \\( x = 3 \\) and \\( x = -3 \\); the upward parabola is above the axis outside the roots.</td></tr>\n              <tr><td>4. So \\( x < -3 \\ \\) or \\( \\ x > 3 \\).</td></tr>\n            </table>\n            <p>The mirror-image case is just as important: \\( x^2 < 9 \\) gives \\( -3 < x < 3 \\) (between the roots). In general, for \\( a > 0 \\): \\( x^2 > a^2 \\Rightarrow x < -a \\) or \\( x > a \\); and \\( x^2 < a^2 \\Rightarrow -a < x < a \\).</p>", "question": "Solve \\( x^2 > 25 \\).", "options": ["\\( x > 5 \\) only", "\\( x < -5 \\) or \\( x > 5 \\)", "\\( -5 < x < 5 \\)", "\\( x > 5 \\) or \\( x > -5 \\)"]}'::jsonb, '{"answer": 1, "explain": "\\( x^2 - 25 > 0 \\Rightarrow (x-5)(x+5) > 0 \\); the region outside the roots is \\( x < -5 \\) or \\( x > 5 \\)."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:learn:21547528', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'learn', 'mcq', 1, '{"readingTitle": "How do you show a solution set on a number line?", "reading": "<p>Marking a solution on a <strong>number line</strong> is a real exam skill (OCR 2019 Q2b). Two things must be right:</p>\n            <ul>\n              <li>The <strong>line/region</strong> covers exactly the solution set.</li>\n              <li>The <strong>circles</strong> at the ends show whether each end value is included: <strong>closed (filled)</strong> for \\( \\le \\) / \\( \\ge \\), <strong>open (empty)</strong> for \\( < \\) / \\( > \\).</li>\n            </ul>\n            <p><strong>Worked example — illustrate \\( -3 \\le x \\le 4 \\):</strong> a line from \\( -3 \\) to \\( 4 \\) with <strong>filled</strong> circles at both ends (both included):</p>\n            <svg viewBox=\"0 0 420 64\" width=\"100%\" style=\"max-width:460px;height:auto;display:block;margin:14px auto\" role=\"img\" aria-label=\"Number line showing minus 3 less than or equal to x less than or equal to 4 with closed circles at minus 3 and 4\">\n              <line x1=\"20\" y1=\"30\" x2=\"405\" y2=\"30\" stroke=\"currentColor\" stroke-width=\"1.5\"/>\n              <line x1=\"66\" y1=\"30\" x2=\"318\" y2=\"30\" stroke=\"currentColor\" stroke-width=\"6\" stroke-opacity=\"0.35\"/>\n              <g stroke=\"currentColor\" stroke-width=\"1\">\n                <line x1=\"30\" y1=\"25\" x2=\"30\" y2=\"35\"/><line x1=\"66\" y1=\"25\" x2=\"66\" y2=\"35\"/><line x1=\"102\" y1=\"25\" x2=\"102\" y2=\"35\"/><line x1=\"138\" y1=\"25\" x2=\"138\" y2=\"35\"/><line x1=\"174\" y1=\"25\" x2=\"174\" y2=\"35\"/><line x1=\"210\" y1=\"25\" x2=\"210\" y2=\"35\"/><line x1=\"246\" y1=\"25\" x2=\"246\" y2=\"35\"/><line x1=\"282\" y1=\"25\" x2=\"282\" y2=\"35\"/><line x1=\"318\" y1=\"25\" x2=\"318\" y2=\"35\"/><line x1=\"354\" y1=\"25\" x2=\"354\" y2=\"35\"/><line x1=\"390\" y1=\"25\" x2=\"390\" y2=\"35\"/>\n              </g>\n              <g font-size=\"12\" fill=\"currentColor\" text-anchor=\"middle\">\n                <text x=\"30\" y=\"52\">-4</text><text x=\"66\" y=\"52\">-3</text><text x=\"102\" y=\"52\">-2</text><text x=\"138\" y=\"52\">-1</text><text x=\"174\" y=\"52\">0</text><text x=\"210\" y=\"52\">1</text><text x=\"246\" y=\"52\">2</text><text x=\"282\" y=\"52\">3</text><text x=\"318\" y=\"52\">4</text><text x=\"354\" y=\"52\">5</text><text x=\"390\" y=\"52\">6</text>\n              </g>\n              <circle cx=\"66\" cy=\"30\" r=\"5.5\" fill=\"currentColor\"/>\n              <circle cx=\"318\" cy=\"30\" r=\"5.5\" fill=\"currentColor\"/>\n            </svg>\n            <p>If the inequality had been \\( -3 < x < 4 \\) (strict), the two end circles would be drawn <strong>open</strong> (empty) instead. Examiners warn every year that an ambiguous circle — neither clearly filled nor clearly empty — loses the mark.</p>", "question": "To show \\( x > 2 \\) on a number line, the circle at \\( 2 \\) should be:", "options": ["closed (filled), with the line going left", "open (empty), with the line going right", "closed (filled), with the line going right", "open (empty), with the line going left"]}'::jsonb, '{"answer": 1, "explain": "\\( > \\) is strict, so \\( 2 \\) is excluded — an open circle — and \\( x > 2 \\) points to larger values, so the line goes right."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:misc:e685901e', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \\( -x > 6 \\Rightarrow x > -6 \\)</p><p><strong>✅ The correct idea:</strong> Dividing by \\( -1 \\) must FLIP the sign. A weak answer keeps \\( > \\); a strong answer writes \\( x < -6 \\). This was the exemplar error of OCR 2024 Q1 — much of the algebra was correct but candidates could not deal with the final negative.</p>", "question": "Solve \\( 2 - (x+1) > 7 \\).", "options": ["\\( x > -6 \\)", "\\( x < -6 \\)", "\\( x > 6 \\)", "\\( x < 6 \\)"]}'::jsonb, '{"answer": 1, "explain": "\\( 2 - x - 1 > 7 \\Rightarrow 1 - x > 7 \\Rightarrow -x > 6 \\); divide by \\( -1 \\) and flip: \\( x < -6 \\)."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:misc:695d6352', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \\( x^2 > 9 \\Rightarrow x > 3 \\)</p><p><strong>✅ The correct idea:</strong> Square-rooting loses the negative arm. A weak answer gives \\( x > 3 \\) only; a strong answer treats it as \\( (x-3)(x+3) > 0 \\) and writes \\( x < -3 \\) or \\( x > 3 \\).</p>", "question": "Solve \\( x^2 > 16 \\).", "options": ["\\( x > 4 \\) only", "\\( x < -4 \\) or \\( x > 4 \\)", "\\( -4 < x < 4 \\)", "\\( x < 4 \\)"]}'::jsonb, '{"answer": 1, "explain": "\\( (x-4)(x+4) > 0 \\); outside the roots: \\( x < -4 \\) or \\( x > 4 \\)."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:misc:09db92a4', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \\( x^2 - x - 6 > 0 \\Rightarrow -2 < x < 3 \\)</p><p><strong>✅ The correct idea:</strong> That is the region for \\( < 0 \\), not \\( > 0 \\). A weak answer picks the wrong region; a strong answer sketches the upward parabola and reads the region ABOVE the axis: \\( x < -2 \\) or \\( x > 3 \\).</p>", "question": "Which region makes an upward parabola positive (\\( y > 0 \\))?", "options": ["Between the roots", "Outside the roots", "At the roots only", "Everywhere"]}'::jsonb, '{"answer": 1, "explain": "An upward parabola is above the axis (positive) outside its two roots."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:misc:a223debb', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Solving \\( \\frac{2x-1}{5} < 1 \\) by adding 1 to only the middle part of a double inequality</p><p><strong>✅ The correct idea:</strong> Every operation must be applied to ALL THREE parts. A weak answer changes one part; a strong answer keeps the chain balanced: multiply all three by 5, add 1 to all three, divide all three by 2.</p>", "question": "When solving \\( \\frac{1}{3} < \\frac{2x-1}{5} < 1 \\), what do you multiply by 5?", "options": ["Only the middle part", "All three parts", "Only the outer two parts", "Nothing — you cannot multiply"]}'::jsonb, '{"answer": 1, "explain": "A double inequality is kept true only if every part receives the same operation."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:misc:92d3f6fe', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Drawing an OPEN circle to show \\( x \\le 4 \\) on a number line</p><p><strong>✅ The correct idea:</strong> \\( \\le \\) includes the end value, so the circle must be CLOSED (filled). A weak answer leaves it open or ambiguous; a strong answer fills it clearly. OCR 2019 Q2b noted markers could not always tell whether a circle was filled in.</p>", "question": "For \\( x \\ge -1 \\), the circle at \\( -1 \\) should be:", "options": ["open (empty)", "closed (filled)", "half-shaded", "a cross"]}'::jsonb, '{"answer": 1, "explain": "\\( \\ge \\) is non-strict, so \\( -1 \\) is included and the circle is closed (filled)."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:tips:35fe12b0', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'tips', 'mcq', 1, '{"readingTitle": "explain — The negative-flip trap (a guaranteed exam mark)", "reading": "<p>OCR 2024 Q1 asked to solve \\( 2 - (x+1) > 7 \\).</p><p><strong>0 / 2 marks:</strong> correct algebra down to \\( -x > 6 \\), then \\( x > -6 \\) — the sign was not flipped.</p><p><strong>Full marks:</strong> \\( -x > 6 \\Rightarrow x < -6 \\). Whenever you divide (or multiply) by a negative, flip the sign and, if you like, sanity-check one value: \\( x = -10 \\) gives \\( 2 - (-9) = 11 > 7 \\) ✓.</p>", "question": "You reach \\( -x > 6 \\). The correct final line is:", "options": ["\\( x > -6 \\)", "\\( x < -6 \\)", "\\( x > 6 \\)", "\\( x < 6 \\)"]}'::jsonb, '{"answer": 1, "explain": "Multiplying by \\( -1 \\) flips \\( > \\) to \\( < \\): \\( x < -6 \\)."}'::jsonb),
('additional-maths:1-4-linear-and-quadratic-inequalities:tips:e49f192a', 'additional-maths', 'additional-maths:1-4-linear-and-quadratic-inequalities', '1.4 Linear and Quadratic Inequalities', 'tips', 'mcq', 1, '{"readingTitle": "tip — A ladder for quadratic inequalities", "reading": "<p>Score every mark on a quadratic inequality with the same four steps:</p><p><strong>1.</strong> Make one side \\( 0 \\). <strong>2.</strong> Factorise to find the critical values. <strong>3.</strong> Sketch the parabola (which way it opens + where it crosses). <strong>4.</strong> Read the region.</p><p>Write \"\\( x < -2 \\) or \\( x > 3 \\)\" — NOT \"\\( -2 > x > 3 \\)\", which is impossible. A quick sketch beside your working is the surest guard against choosing the wrong region.</p>", "question": "For a quadratic inequality, what should you find right after making one side zero?", "options": ["The turning point", "The critical values (roots)", "The discriminant''s sign", "The y-intercept"]}'::jsonb, '{"answer": 1, "explain": "Factorising to the critical values (roots) is step 2; the sketch then tells you the region."}'::jsonb)
